        $api_key = 'DEMO_KEY';
        $url = 'https://api.nasa.gov/planetary/apod?api_key=' . $api_key;

        if (!empty($date)) {
            // Validate date format YYYY-MM-DD
            if (preg_match('/^\d{4}-\d{2}-\d{2}$/', $date)) {
                $url .= '&date=' . $date;
